+jint crac::checkpointable_status() {
+  bool is_checkpointable = true;
+  if ((crac::_generation > 1) &&
+      (crac::_engine->prepare_checkpointable_data_api() == CracEngine::ApiStatus::OK)) {
+      return crac::_engine->get_checkpointable_status();
+  }
+
+  return ready;
+}
